import{_ as a,c as r,o as t,a0 as i}from"./chunks/framework.Bga1nt3p.js";const c="/assets/spark_graph.B7CdjWP0.png",l="/assets/spark_tree.CmJZ0gNO.png",o="/assets/spark_world.DcLzdgfu.png",s="/assets/spark_plugins.CkHt4pVk.png",f=JSON.parse('{"title":"性能分析","description":"","frontmatter":{},"headers":[],"relativePath":"server-maintenance/performance-analysis.md","filePath":"server-maintenance/performance-analysis.md"}'),n={name:"server-maintenance/performance-analysis.md"};function d(p,e,k,m,h,u){return t(),r("div",null,e[0]||(e[0]=[i('<h1 id="性能分析" tabindex="-1">性能分析 <a class="header-anchor" href="#性能分析" aria-label="Permalink to &quot;性能分析&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">提示</p><p>在进行性能分析之前, 请先确保你安装了 <a href="https://spark.lucko.me/download" target="_blank" rel="noreferrer">spark</a> 插件 (一般类 Paper 服务端内置)</p></div><p>Minecraft 服务器的卡顿一般使用 <code>spark</code> 插件进行分析, 该插件可以查看服务器的性能指标, 查看服务器的 GC 回收情况, 列出服务器每个方法调用所消耗的时间 (占比), 可以从中分析出服务器瓶颈之处</p><h2 id="基本性能分析" tabindex="-1">基本性能分析 <a class="header-anchor" href="#基本性能分析" aria-label="Permalink to &quot;基本性能分析&quot;">​</a></h2><p>该栏目的性能分析主要针对的是 TPS 的瓶颈</p><p>以下是开始进行性能分析前的准备工作:</p><ol><li>在 <strong>开始卡顿的时候</strong> 执行 <code>/spark profiler stop</code> 指令, 该指令可以上传服务器的性能数据到 <code>spark</code> 插件的网站上, 方便进行分析</li><li>(若已自动重新开始记录数据, 可不执行) 紧接着执行 <code>/spark profiler start</code> 指令, 重新开始记录性能数据</li><li>等待约 10 ~ 20 分钟后 (最好这一段时间服务器都卡顿), 再次执行 <code>/spark profiler stop</code> 指令, 将这一段时间的性能数据上传到 <code>spark</code> 插件的网站上</li><li>打开聊天栏显示的网址, 开始进行分析</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果你愿意下载大体积的性能分析报告 (spark 插件国内下载较慢), 你可以在卡顿后 10 ~ 20 分钟只进行第一步 (会上传自上一次执行该指令 (若未执行则开服) 到目前的所有性能数据到远程服务器)</p></div><p>接着就要开始分析了</p><p><s>文章里唯一有图片的地方, 后面会补充更多</s></p><h3 id="看曲线" tabindex="-1">看曲线 <a class="header-anchor" href="#看曲线" aria-label="Permalink to &quot;看曲线&quot;">​</a></h3><p>一般来说, <code>spark</code> 报告会有一份曲线图, 你可以只开启 <code>TPS</code>, <code>Entities</code> (实体) 或 <code>TPS</code>, <code>Chunk</code> (区块) 两条曲线搭配看, 观察他们是否有一定的关系规律 (如 TPS 下降时 Entities 上升), 若有则说明 TPS 受另一条曲线的影响</p><p>如下曲线:</p><p><img src="'+c+'" alt="spark 曲线" title="spark 曲线"></p><p>由图可知 TPS 的减少时 Entities 会增加, 说明 TPS 受 Entities (实体) 影响较大, 这时可以考虑优化 实体 相关的插件或配置</p><h3 id="看调用树" tabindex="-1">看调用树 <a class="header-anchor" href="#看调用树" aria-label="Permalink to &quot;看调用树&quot;">​</a></h3><p>最下面的 <code>All View</code> 就是服务器的调用树 (个人起名), 它展示了服务器调用了什么方法, 占用了服务器每tick的百分比 (也有具体的占用时间可以显示出来)</p><p>一般来说, 我们会沿着性能占比最大 (如果两个相近则都要) 的一路往下点, 直到每个节点 (每一个调用的方法/线程叫一个节点, 可以直接粗略理解为每一行) 的占比小到一定程度, 就不继续往下点</p><p>如下是点后的调用树 (Chunk 区块部分可能没截全):</p><p><img src="'+l+'" alt="spark 调用树" title="spark 调用树"></p><p>接着我们自上而下按照点开的顺序开始分析 (一般来说从 <code>net.minecraft.server.MinecraftServer.runServer()</code> 开始):</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>可以直接对类名和方法名进行翻译, 方便理解 对于上下层级占比差不多的方法 (&lt;5%), 可以不看, 只看差别较大的 此处的分析会将 net.minecraft.server 简写为 nms, 方便阅读</p></div><ul><li><code>nms.MinecraftServer.runServer()</code>: 运行服务器的方法, 98.37%</li><li><code>nms.MinecraftServer.tickServer()</code>: 服务器 tick 的主循环方法, 90.38%</li><li><code>nms.MinecraftServer.tickChildren()</code>: 服务器 tick 子线程的方法, 90.16%</li><li><code>nms.level.ServerLevel.tick()</code>: 服务器世界的 tick 方法, 87.52% <ul><li><code>net.minecraft.world.level.entity.EntityTickList.forEach()</code>: 实体 tick 列表的遍历方法, 50.26% <ul><li><code>nms.level.ServerLevel$$Lambda.0x00007f02c7efa408.accept()</code>: 实体 tick 列表的遍历方法的 lambda 表达式, 49.90%</li><li><code>nms.level.ServerLevel.lambda$tick$4()</code>: 实体 tick 方法的 lambda 表达式, 49.90%</li><li><code>...</code> 其它占比差不多的相关方法, 不作展示, 一般也不会看这里</li><li><code>nms.level.ServerLevel.tickNonPassenger()</code>: 实体的 tick 方法 (非乘客), 47.53% <ul><li><code>net.minecraft.world.entity.npc.Villager.tick()</code>: 村民的 tick 方法, 9.70%</li><li><code>net.minecraft.world.entity.monster.Zombie.tick()</code>: 僵尸的 tick 方法, 8.79%</li><li><code>net.minecraft.world.entity.npc.Villager.inactiveTick()</code>: 村民的非活跃 tick 方法, 8.07%</li><li><code>...</code> 其它实体的 tick 方法</li></ul></li></ul></li><li><code>nms.level.ServerChunkCache.tick()</code>: 区块缓存的 tick 方法, 24.20%</li><li><code>nms.level.ServerChunkCache.tickChunks()</code>: 区块缓存的 tick 多个区块的方法, 18.98%</li><li><code>nms.level.ServerChunkCache.tickChunks()</code>: 区块缓存的 tick 多个区块的方法 (再次调用), 17.56% <ul><li><code>net.minecraft.world.level.NaturalSpawner.spawnForChunk()</code>: 区块生物生成的方法, 12.86%</li><li><code>nms.level.ServerLevel.tickChunk()</code>: 单个区块的 tick 方法, 2.04%</li></ul></li></ul></li></ul><p>由此可见, 较多的实体 (尤其是村民和僵尸) 及实体的生成是导致服务器 TPS 较低的主要原因</p><h3 id="看世界" tabindex="-1">看世界 <a class="header-anchor" href="#看世界" aria-label="Permalink to &quot;看世界&quot;">​</a></h3><p>我们可以点击上方的 <code>World</code> 选项卡, 查看世界的实体与区块的详细信息 (如图)</p><p><img src="'+o+'" alt="spark 世界信息" title="spark 世界信息"></p><h4 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h4><p>Summary 部分即整个服务器的世界信息汇总</p><p>从 Entities (total) 可知每个世界的实体数量及总数量</p><p>从 Chunks (total) 可知每个世界的区块数量及总数量</p><p>从 Entity Count 可知每种实体的数量, 由该图可知服务器的 strider (炽足兽), villager (村民), item (物品, 即掉落物) 较多, 可以针对这些方面展开优化</p><h4 id="region" tabindex="-1">Region <a class="header-anchor" href="#region" aria-label="Permalink to &quot;Region&quot;">​</a></h4><p>这里展示了服务器最多实体的若干个区域 (region), 以及该区域内最多实体的区块 (chunk), 管理员可以到这些区块进行调查</p><h3 id="看插件" tabindex="-1">看插件 <a class="header-anchor" href="#看插件" aria-label="Permalink to &quot;看插件&quot;">​</a></h3><p>可以点击<strong>最上方</strong>的 <code>Plugins</code> 选项卡, 查看每个插件占用的性能百分比 (也有调用树, 同理可以根据上面的方法进行分析)</p><p>如图展示了服务器的一部分插件占用信息</p><p><img src="'+s+'" alt="spark 插件信息" title="spark 插件信息"></p><h2 id="内存-gc-分析" tabindex="-1">内存 / GC 分析 <a class="header-anchor" href="#内存-gc-分析" aria-label="Permalink to &quot;内存 / GC 分析&quot;">​</a></h2><p>没写完</p>',40)]))}const _=a(n,[["render",d]]);export{f as __pageData,_ as default};
